# 色

def is_detected_black(color_value: int):
    """ colorの値が黒かどうかを判定する """
    return color_value == color.BLACK


def is_detected_red(color_value: int):
    """ colorの値が赤かどうかを判定する（たまにUNKNOWNと判定することがある） """
    return (color_value == color.RED) or (color_value == color.UNKNOWN)


def is_detected_green(color_value: int):
    """ colorの値が緑かどうかを判定する """
    return color_value == color.GREEN


def is_detected_blue(color_value: int):
    """ colorの値が青かどうかを判定する """
    return color_value == color.BLUE


def any_sensor_detects_by_color(predicate, *ports: int) -> bool:
    """ 判定関数を使用してセンサーのうちの1つでも指定された色が検知されているかを判定する """
    return any(predicate(color_sensor.color(port)) for port in ports)


# 反射率

def is_reflection_in_range(reflection: int, range_min: int, range_max: int):
    """ 最低値と最大値の中に反射率が収まっているか判定する """
    return range_min <= reflection <= range_max


def get_reflection_difference(port1: int, port2: int) -> int:
    """ ポート1とポート2の反射率の差を返す """
    return color_sensor.reflection(port1) - color_sensor.reflection(port2)


def any_sensor_detects_by_reflection(range_min: int, range_max: int, *ports: int) -> bool:
    """ センサーの反射率のうち1つでも指定の範囲に収まっているかを判定する """
    return any(is_reflection_in_range(color_sensor.reflection(port), range_min, range_max) for port in ports)


def all_sensor_detects_by_reflection(range_min: int, range_max: int, *ports: int) -> bool:
    """ センサーの反射率のうちすべてが指定の範囲に収まっているかを判定する """
    return all(is_reflection_in_range(color_sensor.reflection(port), range_min, range_max) for port in ports)


