NOTE_NAME_MAP = {
    "ド": "C",
    "レ": "D",
    "ミ": "E",
    "ファ": "F",
    "ソ": "G",
    "ラ": "A",
    "シ": "B",
}


def get_note_hz(note: str) -> int:
    """
    音名から周波数を取得する

    例:
        get_note_hz("ド4")
        get_note_hz("ド#4")
        get_note_hz("ソ3")
        get_note_hz("ラ#5")
    """

    for jp, en in NOTE_NAME_MAP.items():
        if note.startswith(jp):
            note = en + note[len(jp):]
            break
    else:
        raise ValueError("無効な音名: " + note)

    if len(note) >= 3 and note[1].isdigit() and note[2] == "#":
        note = note[0] + "#" + note[1]

    try:
        return NOTE_HZ_MAP[note]
    except KeyError:
        raise ValueError("対応していない音程: " + note)


async def play_sound(hz: int, time: int):
    """ 指定された周波数の音を再生する """
    await sound.beep(int(hz * 2), time, SOUND_VOLUME)
    await runloop.sleep_ms(1)


def bpm_to_note_durations_ms(bpm: int) -> tuple[int, int, int]:
    """ BPMから4分音符・8分音符・16分音符の長さをミリ秒単位に変換する """
    quarter_note_ms = int(60000 / bpm)
    eighth_note_ms = int(quarter_note_ms / 2)
    sixteenth_note_ms = int(eighth_note_ms / 2)

    return quarter_note_ms, eighth_note_ms, sixteenth_note_ms


