# estimators\orientation_estimator.py
# ────────────────────────────────────────────────────────
def get_data_for_precise_rotation(target_angle: int) -> tuple[int, bool]:
    """ ロボットの姿勢からパワーと誤差を計算する """

    current_yaw_angles = get_yaw()  # 0.1°単位（900で90°）
    diff = target_angle * YAW_SCALE - current_yaw_angles
    is_finished = abs(diff) <= ANGLE_TOLERANCE

    if is_finished:
        return 0, True

    max_power = MIN_ROTATION_POWER * 8  # 5 * 8 = 40

    if 600 > abs(diff) > 300:        # 30～60°
        max_power = MIN_ROTATION_POWER * 4  # 5 * 4 = 20
    elif 300 > abs(diff) > 100:        # 10～30°
        max_power = MIN_ROTATION_POWER * 2  # 5 * 2 = 10
    elif 100 > abs(diff):                        # 10°未満
        max_power = MIN_ROTATION_POWER  # 5 * 1 = 5

    power = clamp(diff * ROTATION_KP, -max_power, max_power)

    if 0 < power < MIN_ROTATION_POWER:
        power = MIN_ROTATION_POWER
    elif -MIN_ROTATION_POWER < power < 0:
        power = -MIN_ROTATION_POWER

    return power, False


