def get_distance_in_mm(port: int):
    """ 距離センサーから距離（mm）を取得する """

    return distance_sensor.distance(port)


def _convert_value_to_mm(value: int, unit: str):
    if unit == DistanceUnit.MM:
        return value
    if unit == DistanceUnit.CM:
        return value * 10
    if unit == DistanceUnit.M:
        return value * 10 * 100

    raise ValueError("Unsupported distance unit: " + unit)


def is_distance_less_than_or_equal(port: int, value: int, unit: str):
    """ 距離が指定の値以下かを判定する（unitにはDistanceUnitを指定可能） """

    distance = get_distance_in_mm(port)

    if distance == -1:
        return False

    value = _convert_value_to_mm(value, unit)

    return distance <= value


def is_distance_greater_than_or_equal(port: int, value: int, unit: str):
    """ 距離が指定の値以上かを判定する（unitにはDistanceUnitを指定可能） """

    distance = get_distance_in_mm(port)

    if distance == -1:
        return False

    value = _convert_value_to_mm(value, unit)

    return distance >= value


