# ────────────────────────────────────────────────────────
# controllers\drive_controller.py
# ────────────────────────────────────────────────────────
async def rotation(degrees: int, power: int = 100):
    """ 回転操作を行う """
    await motor_pair.move_for_degrees(M_PAIR, degrees * 2, 100, velocity=power_percentage_to_velocity(power))


async def precise_rotation(degrees: int):
    """ 正確な回転操作を行う """

    reset_yaw_value()
    await runloop.sleep_ms(WHILE_INTERVAL)  # reset_yaw_valueが実際には非同期更新のため、少し待つ

    while abs(get_yaw()) > 5:
        await runloop.sleep_ms(WHILE_INTERVAL)

    retry_count = 0

    while True:
        power, finished = get_data_for_precise_rotation(degrees)

        if finished or retry_count > 100:  # 約1秒が経過した時点でタイムアウト
            motor_pair.stop(M_PAIR)
            break

        velocity = power_percentage_to_velocity(power)
        motor_pair.move_tank(M_PAIR, velocity, -velocity)

        await runloop.sleep_ms(WHILE_INTERVAL)
        retry_count += 1

    reset_yaw_value()


async def going_straight(distance: int, power: int = 100):
    """ distanceにはcmの距離を記載する """
    await motor_pair.move_for_degrees(M_PAIR, cm_to_degrees(distance), 0, velocity=power_percentage_to_velocity(power))


def move_infinite(power: int = 100):
    """ stop_motorが実行されるまで無限に進む """
    motor_pair.move(M_PAIR, 0, velocity=power_percentage_to_velocity(power))


def tank_move_infinite(left: int, right: int):
    """ left, rightには左右モーターのパワー（%）を指定する """
    motor_pair.move_tank(M_PAIR, power_percentage_to_velocity(left), power_percentage_to_velocity(right))


async def follow_black_line_until(predicate = lambda: False, power: int = 100):
    """ ある条件が満たされるまで黒色の線を追尾する（predicateに永遠にFalseを返す関数を指定すると無限に走行） """

    velocity = power_percentage_to_velocity(power)

    while not predicate():
        diff = get_reflection_difference(port.A, port.B)
        steering = clamp(diff * LINE_TRACE_ROTATION_KP, minimum=-LINE_TRACE_MAX_STEERING, maximum=LINE_TRACE_MAX_STEERING)

        motor_pair.move(M_PAIR, steering, velocity=velocity)

        await runloop.sleep_ms(WHILE_INTERVAL)

    motor_pair.stop(M_PAIR)


def stop_motor():
    """ モーターの動作を停止する """
    motor_pair.stop(M_PAIR)


# ────────────────────────────────────────────────────────
# main.py
# ────────────────────────────────────────────────────────
async def game1():
    await follow_black_line_until(predicate=lambda: False, power=100)


async def game2():
    await follow_black_line_until(predicate=lambda: is_distance_less_than_or_equal(port.F, 25, DistanceUnit.CM), power=100)
    await rotation(degrees=180)
    await follow_black_line_until(predicate=lambda: False, power=100)


runloop.run(play_random_song(), game1())
